const data = result?.data;

{result?.status === "success" && data && (
  <>
    <MetricsBlock title="OCSVM" m={data?.ocsvm} />
    <MetricsBlock title="DBSCAN" m={data?.dbscan} />

    {data?.actual?.map((v, i) => (
      <tr key={i}>
        <td>{i}</td>
        <td>{v}</td>
        <td>{data?.ocsvm?.predictions?.[i]}</td>
        <td>{data?.dbscan?.predictions?.[i]}</td>
      </tr>
    ))}
  </>
)}
